"""promptfoo custom provider for SGA V2 agent."""

import json
import os
import sys
from pathlib import Path

REPO_ROOT = Path(__file__).resolve().parent.parent.parent
sys.path.insert(0, str(REPO_ROOT))

from dotenv import load_dotenv

load_dotenv(REPO_ROOT / ".env")

from prototype.orchestrator import run_agent
from prototype.schema import UserProfile


def call_api(prompt: str, options: dict, context: dict) -> dict:
    """Call the SGA agent and return structured output for promptfoo."""
    config = options.get("config", {})
    vars_ = context.get("vars", {})

    # Build UserProfile from vars (profile overrides per test case)
    profile_kwargs = {}
    for field in [
        "dietary_restrictions",
        "preferred_cuisines",
        "disliked_ingredients",
        "preferred_stores",
    ]:
        if field in vars_:
            val = vars_[field]
            if isinstance(val, str):
                profile_kwargs[field] = json.loads(val)
            else:
                profile_kwargs[field] = val
    for field in ["household_size"]:
        if field in vars_:
            profile_kwargs[field] = int(vars_[field])
    if "notes" in vars_:
        profile_kwargs["notes"] = vars_["notes"]

    profile = UserProfile(**profile_kwargs)
    model = config.get("model") or os.environ.get("SGA_MODEL")

    try:
        result = run_agent(prompt, profile=profile, model=model)
        output = result.model_dump()
        return {
            "output": json.dumps(output, ensure_ascii=False),
            "tokenUsage": {
                "total": result.input_tokens + result.output_tokens,
                "prompt": result.input_tokens,
                "completion": result.output_tokens,
            },
        }
    except Exception as e:
        return {"error": str(e)}

# LOW-04: Glossary miss — agent provides AI-translated fallback
# translate_term returns match_type "none" for lemongrass, agent must label as AI-translated
- description: 'LOW-04: Glossary miss for lemongrass — response includes AI-translated label'
  vars:
    input: "How do you say 'lemongrass' in Chinese?"
  assert:
    # Structural: calls translate_term with lemongrass
    - type: javascript
      value: |
        const parsed = JSON.parse(output);
        return parsed.tool_calls.some(tc =>
          tc.name === 'translate_term' &&
          tc.input.term && tc.input.term.toLowerCase().includes('lemongrass')
        );
      weight: 3
      metric: calls_translate_term_lemongrass

    # Structural: translate_term returns match_type "none"
    - type: javascript
      value: |
        const parsed = JSON.parse(output);
        const translateCall = parsed.tool_calls.find(tc => tc.name === 'translate_term');
        if (!translateCall) return { pass: false, score: 0, reason: 'translate_term not called' };
        const result = translateCall.result;
        return result.match_type === 'none';
      weight: 2
      metric: glossary_miss_confirmed

    # Content: response includes Chinese translation for lemongrass
    - type: javascript
      value: |
        const parsed = JSON.parse(output);
        const text = parsed.response_text;
        const hasChinese = /[\u4e00-\u9fff]/.test(text);
        return hasChinese;
      weight: 2
      metric: chinese_translation_provided

    # Content: response includes "AI-translated" or equivalent label
    - type: javascript
      value: |
        const parsed = JSON.parse(output);
        const text = parsed.response_text.toLowerCase();
        return text.includes('ai-translated') || text.includes('ai translated') ||
          text.includes('not in glossary') || text.includes('not glossary') ||
          text.includes('my own translation') || text.includes('not verified');
      weight: 3
      metric: ai_translated_label

