        const surroundingEnd = Math.min(textLower.length, match.index + term.length + 80);
        const surrounding = text.substring(surroundingStart, surroundingEnd);
        if (!contextPattern.test(surrounding)) {
          violations.push(term);
          break;
        }
      }
